def validate_binary_label(label: Any) -> bool:
    return isinstance(label, bool)

def validate_ordinal_label(label: Any, min_val: int = 1, max_val: int = 5) -> bool:
    return isinstance(label, int) and min_val <= label <= max_val

# Anchor definitions lock ordinal meaning for annotators
ORDINAL_ANCHORS = {
    1: "Response is wrong, misleading, or harmful",
    2: "Major gaps or errors; not usable as-is",
    3: "Partially correct; requires significant editing",
    4: "Minor issues only; usable with light editing",
