}

def validate_spans(agent_output: str, spans: list[Span]) -> list[str]:
    errors = []
    for s in spans:
        if s.start < 0 or s.end > len(agent_output):
            errors.append(f"Span [{s.start},{s.end}) out of range for output length {len(agent_output)}")
        if s.start >= s.end:
            errors.append(f"Span [{s.start},{s.end}) is empty or inverted")
        if s.label not in ALLOWED_SPAN_LABELS:
            errors.append(f"Unknown label '{s.label}'")
    return errors

ALLOWED_SPAN_LABELS = {"factual_error", "unsafe", "off_topic", "incomplete", "hallucination"}

from fastapi import FastAPI, HTTPException
from pydantic import BaseModel
import sqlite3

app = FastAPI()
db = init_annotation_db()


class AnnotationRequest(BaseModel):
    session_id: str
    turn_index: int
    messages: list[dict]
    agent_output: str
    annotation_type: str
    label: object
    dimension: str | None = None
    annotator_id: str | None = None


@app.post("/annotations", status_code=201)
def submit_annotation(req: AnnotationRequest):
    try:
        ann_type = AnnotationType(req.annotation_type)
    except ValueError:
        raise HTTPException(400, f"Unknown annotation_type: {req.annotation_type}")

    # Validate label shape
    if ann_type == AnnotationType.BINARY and not isinstance(req.label, bool):
        raise HTTPException(400, "Binary label must be true/false")
    if ann_type == AnnotationType.ORDINAL:
        if not isinstance(req.label, int) or not (1 <= req.label <= 5):
            raise HTTPException(400, "Ordinal label must be integer 1–5")

    rec = AnnotationRecord.make(
        session_id=req.session_id,
        turn_index=req.turn_index,
        messages=req.messages,
        agent_output=req.agent_output,
        annotation_type=ann_type,
        label=req.label,
        dimension=req.dimension,
        annotator_id=req.annotator_id,
    )
    insert_annotation(db, rec)
    return {"annotation_id": rec.annotation_id}


